// Get all items from Merge
const allItems = $input.all();

// Parse result from first item
const parseItem = allItems[0]?.json || {};
const fullText = parseItem.markdown || parseItem.text || '';
const pageCount = parseItem.pageCount || 0;

// Analysis from second item
const analysisItem = allItems[1]?.json || {};
const standardsMapping = analysisItem.markdown || analysisItem.answer || analysisItem.text || '';

// Get trigger data
const triggerData = $('New Document').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Identify document type
let docType = 'Unknown';
const typeMatch = standardsMapping.match(/document type[:\s]+([^\n]+)/i);
if (typeMatch) docType = typeMatch[1].trim();

// Count standards with evidence
const standardAreas = ['MISSION', 'STUDENT ACHIEVEMENT', 'CURRICULUM', 'RESOURCES', 'CONTINUOUS IMPROVEMENT'];
let standardsAddressed = [];
let standardsGaps = [];

standardAreas.forEach(area => {
  const areaRegex = new RegExp(area + '[^]*?(YES|NO)', 'i');
  const match = standardsMapping.match(areaRegex);
  if (match && match[1].toUpperCase() === 'YES') {
    standardsAddressed.push(area);
  } else {
    standardsGaps.push(area);
  }
});

// Count evidence strength
let strongEvidence = (standardsMapping.match(/STRONG/gi) || []).length;
let moderateEvidence = (standardsMapping.match(/MODERATE/gi) || []).length;
let weakEvidence = (standardsMapping.match(/WEAK/gi) || []).length;

// Count gaps by priority
let highGaps = (standardsMapping.match(/HIGH.*?priority/gi) || []).length;
let mediumGaps = (standardsMapping.match(/MEDIUM.*?priority/gi) || []).length;

// Extract compliance score
let complianceScore = 5;
const scoreMatch = standardsMapping.match(/compliance score[:\s]*(\d+)/i) ||
                   standardsMapping.match(/overall.*?(\d+).*?(?:out of|\/).*?10/i);
if (scoreMatch) complianceScore = parseInt(scoreMatch[1]);

// Determine overall status
let status = 'Acceptable';
if (complianceScore >= 8) status = 'Strong Evidence';
else if (complianceScore >= 6) status = 'Adequate';
else if (complianceScore >= 4) status = 'Needs Improvement';
else status = 'Critical Gaps';

return [{
  json: {
    fileName: fileName,
    fileId: fileId,
    documentType: docType,
    pageCount: pageCount,
    textLength: fullText.length,
    standardsAddressed: standardsAddressed.join(', ') || 'None identified',
    standardsAddressedCount: standardsAddressed.length,
    standardsGaps: standardsGaps.join(', ') || 'None',
    standardsGapsCount: standardsGaps.length,
    strongEvidence: strongEvidence,
    moderateEvidence: moderateEvidence,
    weakEvidence: weakEvidence,
    highPriorityGaps: highGaps,
    mediumPriorityGaps: mediumGaps,
    complianceScore: complianceScore,
    status: status,
    standardsMapping: standardsMapping,
    processedAt: new Date().toISOString()
  }
}];

